// Parse the Supervisor Agent output and structure it as JSON
const items = $input.all();
const results = [];

for (const item of items) {
  const agentOutput = item.json.output || {};

  // Structure the proposal data
  const structuredProposal = {
    title: agentOutput.title || 'Untitled Proposal',
    problem_statement: agentOutput.problem_statement || agentOutput.problemStatement || '',
    objectives: agentOutput.objectives || agentOutput.research_objectives || [],
    hypotheses: agentOutput.hypotheses || agentOutput.testable_hypotheses || [],
    methodology: agentOutput.methodology || {},
    innovation: agentOutput.innovation || agentOutput.expected_contributions || '',
    work_plan: agentOutput.work_plan || agentOutput.workPlan || {},
    budget: agentOutput.budget || agentOutput.budget_justification || {},
    impact: agentOutput.impact || agentOutput.impact_assessment || {},
    commercialization_strategy: agentOutput.commercialization_strategy || agentOutput.commercializationStrategy || '',
    stakeholder_engagement: agentOutput.stakeholder_engagement || agentOutput.stakeholderEngagement || '',
    ethical_considerations: agentOutput.ethical_considerations || agentOutput.ethicalConsiderations || '',
    sustainability_plan: agentOutput.sustainability_plan || agentOutput.sustainabilityPlan || ''
  };

  results.push({
    json: structuredProposal
  });
}

return results;
